#include<bits/stdc++.h>
using namespace std;
long long dfn[500010],fa[500010],d[500010],siz[500010],son[500010],top[500010],dfncnt,val[500010],rnk[500010];
vector<long long> mp[500010];
void dfs1(long long x,long long f=0)
{
    son[x]=-1;
    siz[x]=1;
    for(long long i:mp[x])
    {
        if(i!=f)
        {
            fa[i]=x;
            d[i]=d[x]+1;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(long long i:mp[x])
        {
            if(i!=son[x]&&i!=fa[x])
            {
                dfs2(i,i);
            }
        }
    }
}
struct segment_tree
{
	struct node
	{
		long long l,r,sum,max1;
	}a[500010];
	void init(long long x,long long l,long long r)
	{
		long long mid=(l+r)>>1;
		a[x].l=l;
		a[x].r=r;
		if(l==r)
		{
			a[x].sum=a[x].max1=val[rnk[l]];
			return;
		}
		init(x<<1,l,mid);
		init(x<<1|1,mid+1,r);
		a[x].sum+=a[x<<1].sum;
		a[x].sum+=a[x<<1|1].sum;
        a[x].max1=max(a[x<<1].max1,a[x<<1|1].max1);
	}
	void update(long long x,long long l,long long r,long long z)
	{
		if(a[x].l==a[x].r)
		{
			a[x].sum=a[x].max1=z;
			return;
		}
		long long mid=(a[x].l+a[x].r)>>1;
		if(l<=mid)
		{
			update(x<<1,l,r,z);
		}
		if(r>mid)
		{
			update(x<<1|1,l,r,z);
		}
		a[x].sum=a[x<<1].sum;
		a[x].sum+=a[x<<1|1].sum;
        a[x].max1=max(a[x<<1].max1,a[x<<1|1].max1);
	}
	long long getsum(long long x,long long l,long long r)
	{
		if(a[x].l>=l&&a[x].r<=r)
		{
			return a[x].sum;
		}
		long long mid=(a[x].l+a[x].r)/2,ans=0;
		if(l<=mid)
		{
			ans=getsum(x<<1,l,r);
		}
		if(r>mid)
		{
			ans+=getsum(x<<1|1,l,r);
		}
		return ans;
	}
	long long getmax(long long x,long long l,long long r)
	{
		if(a[x].l>=l&&a[x].r<=r)
		{
			return a[x].max1;
		}
		long long mid=(a[x].l+a[x].r)/2,ans=-1e15;
		if(l<=mid)
		{
			ans=max(ans,getmax(x<<1,l,r));
		}
		if(r>mid)
		{
			ans=max(ans,getmax(x<<1|1,l,r));
		}
		return ans;
	}
}t;
long long sum(long long x,long long y)
{
    return x+y;
}
long long getmax(long long x,long long y)
{
    long long tx=top[x],ty=top[y],ans=-1e15;
    while(tx!=ty)
    {
        if(d[tx]>=d[ty])
        {
            ans=max(ans,t.getmax(1,dfn[tx],dfn[x]));
            x=fa[tx];
        }
        else
        {
            ans=max(ans,t.getmax(1,dfn[ty],dfn[y]));
            y=fa[ty];
        }
        tx=top[x];
        ty=top[y];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans=max(ans,t.getmax(1,dfn[x],dfn[y]));
    return ans;
}
long long getsum(long long x,long long y)
{
    long long tx=top[x],ty=top[y],ans=0;
    while(tx!=ty)
    {
        if(d[tx]>=d[ty])
        {
            ans=sum(ans,t.getsum(1,dfn[tx],dfn[x]));
            x=fa[tx];
        }
        else
        {
            ans=sum(ans,t.getsum(1,dfn[ty],dfn[y]));
            y=fa[ty];
        }
        tx=top[x];
        ty=top[y];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans=sum(ans,t.getsum(1,dfn[x],dfn[y]));
    return ans;
}
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&val[i]);
    }
    dfs1(1);
    dfs2(1,1);
    t.init(1,1,n);
    long long q;
    scanf("%lld",&q);
    while(q--)
    {
        string s;
        long long x,y;
        cin>>s>>x>>y;
        if(s=="CHANGE")
        {
            t.update(1,dfn[x],dfn[x],y);
        }
        else if(s=="QMAX")
        {
            printf("%lld\n",getmax(x,y));
        }
        else
        {
            printf("%lld\n",getsum(x,y));
        }
    }
    return 0;
}
